            pseudoEffect.name = limbName + " Limb Control";

            // Add expression to IK Angles control
            var ikAnglesControl = pseudoEffect.property("IK Angles");
            ikAnglesControl.expression =
                "var ctrlLayer = thisComp.layer(\"" + limbName + " CTRL\");\n" +
                "var upperLimbLength = ctrlLayer.effect(\"" + limbName + " Limb Control\")(\"Upper Limb Length\").value;\n" +
                "var lowerLimbLength = ctrlLayer.effect(\"" + limbName + " Limb Control\")(\"Lower Limb Length\").value;\n" +
                "var goal = ctrlLayer;\n" +
                "var flip = ctrlLayer.effect(\"" + limbName + " Limb Control\")(\"Flip IK\").value;\n" +
                "// Function to calculate world position\n" +
                "function worldPos(layer) {\n" +
                "    return layer.toWorld(layer.anchorPoint);\n" +
                "}\n" +
                "// Function to calculate rotation angle between two points\n" +
                "function rotationFunction(pointA, pointB) {\n" +
                "    var diff = pointB - pointA;\n" +
                "    return Math.atan2(diff[1], diff[0]);\n" +
                "}\n" +
                "// Get the initial positions\n" +
                "var upperLimbInitialPos = thisComp.layer(\"" + limbName + "\").position; // A\n" +
                "var lowerLimbInitialPos = upperLimbInitialPos + [0, upperLimbLength]; // B\n" +
                "var goalPos = goal.toWorld(goal.anchorPoint); // C\n" +
                "// Calculate the distances\n" +
                "var upperToLowerDist = upperLimbLength; // Distance from upper limb to lower limb\n" +
                "var lowerToGoalDist = lowerLimbLength; // Distance from lower limb to goal\n" +
                "var upperToGoalDist = length(goalPos - upperLimbInitialPos); // Distance from upper limb to goal\n" +
                "// Law of Cosines\n" +
                "var LofC = (upperToLowerDist * upperToLowerDist - lowerToGoalDist * lowerToGoalDist + upperToGoalDist * upperToGoalDist) / (2 * upperToGoalDist);\n" +
                "var midPointIK = upperToGoalDist - LofC;\n" +
                "var angleB = Math.acos(Math.max(-1, Math.min(1, midPointIK / lowerToGoalDist))); // Angle B in radians\n" +
                "var angleA = Math.acos(Math.max(-1, Math.min(1, LofC / upperToLowerDist))); // Angle A in radians\n" +
                "// Calculate rotations\n" +
                "var lowerLimbRotationAngle;\n" +
                "if (flip == 1) {\n" +
                "    lowerLimbRotationAngle = angleB + angleA;\n" +
                "} else {\n" +
                "    lowerLimbRotationAngle = -(angleB + angleA);\n" +
                "}\n" +
                "var upperLimbRotationAngle;\n" +
                "if (flip == 1) {\n" +
                "    upperLimbRotationAngle = -angleA;\n" +
                "} else {\n" +
                "    upperLimbRotationAngle = angleA;\n" +
                "}\n" +
                "var uLimbToIKLineAngle = rotationFunction(upperLimbInitialPos, goalPos); // Angle between Upper Limb and IK Line\n" +
                "// Calculate the final rotation angles\n" +
                "var upperLimbRotation = radiansToDegrees(uLimbToIKLineAngle) + radiansToDegrees(upperLimbRotationAngle) - 90;\n" +
                "var lowerLimbRotation = radiansToDegrees(lowerLimbRotationAngle) + upperLimbRotation;\n" +
                "// Output the angles in radians\n" +
                "var ikAngles = [upperLimbRotation, lowerLimbRotation];\n" +
                "ikAngles";
            
  
